{{
(function() {
    function decode(data) {
        if (!data) return null;
        try { return atob(data); } catch(e) { return data; }
    }
    function parseJSONL(text) {
        if (!text) return [];
        var out = [];
        text.replace(/\r\n/g, '\n').split('\n').forEach(function(line) {
            line = line.trim();
            if (!line) return;
            try { out.push(JSON.parse(line)); } catch(e) {}
        });
        return out;
    }
    function parseJSON(data) {
        if (!data) return {};
        try { return JSON.parse(decode(data)); } catch(e) { return {}; }
    }
    function safeFile(q) {
        try { return q && q.data && q.data.fileData; } catch(e) { return null; }
    }
    return {
        "inventory":          parseJSONL(decode(safeFile(inventory))),
			"shadow_ai":  parseJSON(safeFile(shadow)),
        "inventory_enriched": parseJSONL(decode(safeFile(inventory_enriched))),
        "compliance":         parseJSONL(decode(safeFile(compliance))),
        "model_catalogue":    parseJSONL(decode(safeFile(model_catalogue))),
        "report":             parseJSON(safeFile(report))
    };
})()
}}
